#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
const int N=1e5+10,M=3e5+10,INF=0x3f3f3f3f;int Lg[N],n,m; LL W;
int siz[N],mxs[N],dep[N],fa[N],top[N],idx[N],cgt,V[N],head[N],des[N<<1],nxt[N<<1],val[N<<1],cdt;
inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);} bool vis[M];
inline void ins(const int &x,const int &y,const int &z)
{
//	printf("%d' %d' %d\n",x,y,z);
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}
inline void dfs1(const int &u=1,const int &f=0)
{
	siz[u]=1;dep[u]=dep[fa[u]=f]+1;int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];V[v]=val[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
//	printf("%d\n",u);
	top[u]=tp;idx[u]=++cdt;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);
}
struct Edge{int u,v,w;inline bool operator<(const Edge&Q)const{return w<Q.w;}}E[M];
struct Pair
{
	int x,y;
	inline Pair(const int &X=-INF,const int &Y=-INF){x=X;y=Y;}
	inline Pair operator + (const Pair&Q)const
	{
		if(x>Q.x)
		{
			if(y>Q.x)return Pair(x,y);
			if(y<Q.x)return Pair(x,Q.x);
			return Pair(x,max(y,Q.y));
		}
		if(x<Q.x)
		{
			if(Q.y>x)return Pair(Q.x,Q.y);
			if(Q.y<x)return Pair(Q.x,x);
			return Pair(Q.x,max(y,Q.y));
		}
		return Pair(x,max(y,Q.y));
	}
}st[18][N];
inline void Init()
{
	Lg[0]=-1;rep(1,n,i)Lg[i]=Lg[i>>1]+1,st[0][idx[i]].x=V[i];
	rep(1,Lg[n],j)rep(1,n-(1<<j)+1,i)st[j][i]=st[j-1][i]+st[j-1][i+(1<<(j-1))];
}
inline Pair qry(const int &l,const int &r){int len=Lg[r-l+1];return st[len][l]+st[len][r-(1<<len)+1];}
inline Pair Qry(int u,int v)
{
	Pair res;while(top[u]!=top[v])
	{
		if(dep[top[u]]<dep[top[v]]){int tmp(u);u=v;v=tmp;}
		res=res+qry(idx[top[u]],idx[u]);u=fa[top[u]];
	}
//	printf("UV:: %d %d %d\n",u,v,(res+qry(7,7)).x);
//	printf("%d %d\n",res.x,res.y);
//	printf("%d %d\n",st[1][4].x,st[1][4].y);
	if(u==v)return res;if(dep[u]<dep[v]){int tmp(u);u=v;v=tmp;}
	return res+qry(idx[v]+1,idx[u]);
}
int main()
{
//	FIN("data.in");FOUT("mine.out");
	n=read();m=read();rep(1,n,i)fa[i]=i;
	rep(1,m,i)E[i].u=read(),E[i].v=read(),E[i].w=read();std::sort(E+1,E+m+1);
	int tot=0;rep(1,m,i)
	{
		int U=fnd(E[i].u),V=fnd(E[i].v);if(U==V)continue;vis[i]=true;
		fa[U]=V;W+=E[i].w;ins(E[i].u,E[i].v,E[i].w);if((++tot)==n-1)break;
	}
	dfs1();dfs2();Init(); LL ans=1e18;
//	rep(1,n,i)printf("%d ",V[i]);puts("");
//	rep(1,n,i)printf("%d ",fa[i]);puts("");
//	rep(1,n,i)printf("%d ",idx[i]);puts("");
//	rep(1,n,i)printf("(%d,%d) ",st[0][i].x,st[0][i].y);puts("");
//	rep(1,n,i)printf("(%d,%d) ",st[1][i].x,st[1][i].y);puts("");
//	while(true)
//	{
//		int l=read(),r=read();Pair tmp=qry(l,r);
//		printf("%d %d\n",tmp.x,tmp.y);
//	}
	rep(1,m,i)if(!vis[i])
	{
		Pair tmp=Qry(E[i].u,E[i].v);
//		printf("%d --> %d :: (%d,%d)\n",E[i].u,E[i].v,tmp.x,tmp.y);
		chkmin(ans,0ll+E[i].w-(tmp.x==E[i].w?tmp.y:tmp.x));
	}
	printf("%lld\n",W+ans);return 0;
}
